```java
import java.text.NumberFormat;
import java.util.Locale;

// Abstract class
abstract class Employee {
    protected int id;
    protected String name;
    protected static int totalEmployees = 0;

    Employee(int id, String name) {
        this.id = id;
        this.name = name;
        totalEmployees++;
    }

    // Abstract methods
    abstract double calculateSalary();
    abstract void displayInfo();

    // Concrete method
    void showBasicInfo() {
        System.out.println("Employee ID: " + id);
        System.out.println("Employee Name: " + name);
    }

    static int getTotalEmployees() {
        return totalEmployees;
    }
}

// Full-time Employee Implementation
class FullTimeEmployee extends Employee {
    private double monthlySalary;
    private double bonus;

    FullTimeEmployee(int id, String name, double monthlySalary, double bonus) {
        super(id, name);
        this.monthlySalary = monthlySalary;
        this.bonus = bonus;
    }

    @Override
    double calculateSalary() {
        return monthlySalary + bonus;
    }

    @Override
    void displayInfo() {
        showBasicInfo();
        System.out.println("Type: Full-Time Employee");
        System.out.println("Monthly Salary: ₹" + formatCurrency(monthlySalary));
        System.out.println("Bonus: ₹" + formatCurrency(bonus));
        System.out.println("Total Salary: ₹" + formatCurrency(calculateSalary()));
        System.out.println("Benefits: Health Insurance, Provident Fund, Paid Leave");
    }

    private String formatCurrency(double amount) {
        NumberFormat formatter = NumberFormat.getCurrencyInstance(new Locale("en", "IN"));
        return formatter.format(amount);
    }
}

// Part-time Employee Implementation
class PartTimeEmployee extends Employee {
    private double hourlyRate;
    private int hoursWorked;

    PartTimeEmployee(int id, String name, double hourlyRate, int hoursWorked) {
        super(id, name);
        this.hourlyRate = hourlyRate;
        this.hoursWorked = hoursWorked;
    }

    @Override
    double calculateSalary() {
        return hourlyRate * hoursWorked;
    }

    @Override
    void displayInfo() {
        showBasicInfo();
        System.out.println("Type: Part-Time Employee");
        System.out.println("Hourly Rate: ₹" + hourlyRate);
        System.out.println("Hours Worked: " + hoursWorked + " hours");
        System.out.println("Total Salary: ₹" + calculateSalary());
        System.out.println("Benefits: Flexible hours, No health insurance");
    }
}

// Contract Employee Implementation
class ContractEmployee extends Employee {
    private double contractAmount;
    private int contractDuration;  // in months

    ContractEmployee(int id, String name, double contractAmount, int contractDuration) {
        super(id, name);
        this.contractAmount = contractAmount;
        this.contractDuration = contractDuration;
    }

    @Override
    double calculateSalary() {
        return contractAmount / contractDuration;
    }

    @Override
    void displayInfo() {
        showBasicInfo();
        System.out.println("Type: Contract Employee");
        System.out.println("Contract Amount: ₹" + contractAmount);
        System.out.println("Contract Duration: " + contractDuration + " months");
        System.out.println("Monthly Salary: ₹" + String.format("%.2f", calculateSalary()));
        System.out.println("Benefits: No benefits, project-based work");
    }
}

// Manager class demonstrating runtime polymorphism
class PayrollSystem {
    void processSalary(Employee employee) {
        System.out.println("\n" + "=".repeat(50));
        employee.displayInfo();
        System.out.println("=".repeat(50));
    }
}

public class AbstractClassDemo {
    public static void main(String[] args) {
        System.out.println("=== Employee Management System ===\n");

        // Creating employees
        Employee emp1 = new FullTimeEmployee(101, "Rajesh Kumar", 50000, 10000);
        Employee emp2 = new PartTimeEmployee(102, "Priya Sharma", 500, 80);
        Employee emp3 = new ContractEmployee(103, "Amit Patel", 300000, 6);

        // Runtime polymorphism - array of abstract class type
        Employee[] employees = {emp1, emp2, emp3};

        PayrollSystem payroll = new PayrollSystem();

        // Process payroll for all employees
        for (Employee emp : employees) {
            payroll.processSalary(emp);
        }

        // Demonstrate dynamic method dispatch
        System.out.println("\n=== Demonstrating Dynamic Method Dispatch ===");
        Employee employee;

        employee = new FullTimeEmployee(104, "Sneha Reddy", 60000, 15000);
        System.out.println("\nCalling through FullTimeEmployee reference:");
        employee.displayInfo();  // Calls FullTimeEmployee's version

        employee = new PartTimeEmployee(105, "Vikram Singh", 600, 60);
        System.out.println("\nCalling through PartTimeEmployee reference:");
        employee.displayInfo();  // Calls PartTimeEmployee's version

        // Static method call
        System.out.println("\n=== Statistics ===");
        System.out.println("Total Employees Processed: " + Employee.getTotalEmployees());

        // Calculate total payroll
        double totalPayroll = 0;
        for (Employee emp : employees) {
            totalPayroll += emp.calculateSalary();
        }
        System.out.println("Total Monthly Payroll: ₹" + String.format("%.2f", totalPayroll));

        // Demonstrating that abstract class cannot be instantiated
        // Employee e = new Employee(999, "Test");  // COMPILATION ERROR
    }
}
```
